<?php
require_once __DIR__.'/auth.php';
require_once __DIR__.'/partials/layout.php';
require_role('kabag');

if($_SERVER['REQUEST_METHOD']==='POST'){
 verify_csrf();$action=(string)($_POST['action']??'');
 if($action==='create'||$action==='update'){
   $id=(int)($_POST['id']??0);$nama=trim((string)($_POST['nama']??''));$email=strtolower(trim((string)($_POST['email']??'')));$username=trim((string)($_POST['username']??''));$role=(string)($_POST['role']??'staff');$password=(string)($_POST['password']??'');
   if($nama===''||!filter_var($email,FILTER_VALIDATE_EMAIL)||!preg_match('/^[a-zA-Z0-9._-]{3,50}$/',$username)||!in_array($role,['kabag','staff'],true)){set_flash('danger','Data anggota belum valid.');redirect('pengguna.php');}
   if($action==='create'&&strlen($password)<8){set_flash('danger','Password anggota baru minimal 8 karakter.');redirect('pengguna.php');}
   $q=$koneksi->prepare('SELECT id FROM users WHERE (username=? OR email=?) AND id<>? LIMIT 1');$q->bind_param('ssi',$username,$email,$id);$q->execute();if($q->get_result()->num_rows){set_flash('warning','Username atau email sudah digunakan.');redirect('pengguna.php');}
   if($action==='create'){$hash=password_hash($password,PASSWORD_DEFAULT);$q=$koneksi->prepare('INSERT INTO users(nama,email,role,username,password,created) VALUES(?,?,?,?,?,NOW())');$q->bind_param('sssss',$nama,$email,$role,$username,$hash);$ok=$q->execute();}
   else{
     if($id===(int)$_SESSION['id']&&$role!=='kabag'){set_flash('warning','Anda tidak dapat menurunkan role akun yang sedang digunakan.');redirect('pengguna.php');}
     if($password!==''){if(strlen($password)<8){set_flash('danger','Password baru minimal 8 karakter.');redirect('pengguna.php');}$hash=password_hash($password,PASSWORD_DEFAULT);$q=$koneksi->prepare('UPDATE users SET nama=?,email=?,role=?,username=?,password=? WHERE id=?');$q->bind_param('sssssi',$nama,$email,$role,$username,$hash,$id);}
     else{$q=$koneksi->prepare('UPDATE users SET nama=?,email=?,role=?,username=? WHERE id=?');$q->bind_param('ssssi',$nama,$email,$role,$username,$id);}
     $ok=$q->execute();if($ok&&$id===(int)$_SESSION['id']){$_SESSION['nama']=$nama;$_SESSION['email']=$email;$_SESSION['username']=$username;}
   }
   set_flash($ok?'success':'danger',$ok?($action==='create'?'Anggota berhasil ditambahkan.':'Data anggota berhasil diperbarui.'):'Data anggota gagal disimpan.');redirect('pengguna.php');
 }
 if($action==='delete'){
   $id=(int)($_POST['id']??0);
   if($id===(int)$_SESSION['id']){set_flash('warning','Akun yang sedang digunakan tidak dapat dihapus.');redirect('pengguna.php');}
   $q=$koneksi->prepare('SELECT role,foto_profile,(SELECT COUNT(*) FROM arsip WHERE uploaded_by=users.id) archive_count FROM users WHERE id=?');$q->bind_param('i',$id);$q->execute();$user=$q->get_result()->fetch_assoc();
   if(!$user){set_flash('warning','Anggota tidak ditemukan.');redirect('pengguna.php');}
   if((int)$user['archive_count']>0){set_flash('warning','Anggota tidak dapat dihapus karena masih menjadi pengunggah arsip. Ubah data arsip terlebih dahulu.');redirect('pengguna.php');}
   if($user['role']==='kabag'&&(int)db_scalar($koneksi,"SELECT COUNT(*) FROM users WHERE role='kabag'")<=1){set_flash('warning','Kepala Bagian terakhir tidak dapat dihapus.');redirect('pengguna.php');}
   $q=$koneksi->prepare('DELETE FROM users WHERE id=?');$q->bind_param('i',$id);$ok=$q->execute();if($ok&&$user['foto_profile'])delete_uploaded_file('profile/'.$user['foto_profile']);
   set_flash($ok?'success':'danger',$ok?'Anggota berhasil dihapus.':'Anggota gagal dihapus.');redirect('pengguna.php');
 }
}
$users=[];$r=mysqli_query($koneksi,"SELECT u.id,u.nama,u.email,u.role,u.username,u.created,u.foto_profile,COUNT(a.id_arsip) archive_count FROM users u LEFT JOIN arsip a ON a.uploaded_by=u.id GROUP BY u.id,u.nama,u.email,u.role,u.username,u.created,u.foto_profile ORDER BY u.nama");
if($r)while($x=mysqli_fetch_assoc($r))$users[]=$x;
$kabag=0;foreach($users as $u)if($u['role']==='kabag')$kabag++;
render_app_start('Anggota','Kelola akun dan hak akses pengguna aplikasi.','pengguna.php'); ?>
<section class="hero"><div class="hero-copy"><span class="hero-kicker">Manajemen Tim</span><h2>Pastikan setiap anggota memiliki akses yang tepat.</h2><p>Kepala Bagian dapat menambah staf, memperbarui identitas, mengganti role, dan menonaktifkan akun yang tidak lagi digunakan.</p></div><div class="hero-actions"><button class="btn btn-light" data-modal-open="createUser"><i class="fa-solid fa-user-plus"></i> Tambah Anggota</button></div></section>
<section class="stats-grid"><article class="stat-card"><span class="stat-icon blue"><i class="fa-solid fa-users"></i></span><div class="stat-copy"><strong><?=count($users)?></strong><span>Total anggota</span></div></article><article class="stat-card"><span class="stat-icon purple"><i class="fa-solid fa-user-tie"></i></span><div class="stat-copy"><strong><?=$kabag?></strong><span>Kepala Bagian</span></div></article><article class="stat-card"><span class="stat-icon green"><i class="fa-solid fa-user-check"></i></span><div class="stat-copy"><strong><?=count($users)-$kabag?></strong><span>Staf aktif</span></div></article><article class="stat-card"><span class="stat-icon orange"><i class="fa-solid fa-box-archive"></i></span><div class="stat-copy"><strong><?=(int)db_scalar($koneksi,'SELECT COUNT(*) FROM arsip')?></strong><span>Arsip tim</span></div></article></section>
<section class="panel section-gap"><header class="panel-header"><div class="panel-title"><h2>Daftar anggota</h2><p>Akun yang memiliki arsip tidak dapat langsung dihapus.</p></div><div class="toolbar"><label class="search-box"><i class="fa-solid fa-magnifying-glass"></i><input class="input" type="search" placeholder="Cari nama, email, atau role..." data-live-search=".user-card" data-empty-target="#userSearchEmpty"></label><button class="btn btn-primary" data-modal-open="createUser"><i class="fa-solid fa-plus"></i> Tambah</button></div></header><div class="panel-body">
<div class="user-grid"><?php foreach($users as $u):$av=avatar_src($u['foto_profile']);?><article class="user-card" data-search="<?=e($u['nama'].' '.$u['email'].' '.$u['username'].' '.$u['role'])?>"><div class="user-card-head"><span class="avatar avatar-sm"><?php if($av):?><img src="<?=e($av)?>" alt=""><?php else:?><?=e(initials($u['nama']))?><?php endif;?></span><div class="user-card-copy"><h3><?=e($u['nama'])?></h3><p><?=e($u['email'])?></p></div><span class="badge <?=$u['role']==='kabag'?'badge-primary':'badge-success'?>"><?=e($u['role']==='kabag'?'Kepala Bagian':'Staf')?></span></div><div class="card-meta"><span><i class="fa-solid fa-at"></i> <?=e($u['username'])?></span><span><i class="fa-solid fa-box-archive"></i> <?=(int)$u['archive_count']?> arsip</span></div><div class="card-actions"><button class="btn btn-outline btn-sm" onclick='editUser(<?=json_encode(["id"=>(int)$u["id"],"nama"=>$u["nama"],"email"=>$u["email"],"username"=>$u["username"],"role"=>$u["role"]],JSON_HEX_APOS|JSON_HEX_QUOT)?>)'><i class="fa-solid fa-pen"></i> Edit</button><form method="post" style="margin-left:auto"><?=csrf_field()?><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?=(int)$u['id']?>"><button class="btn btn-danger btn-sm" type="submit" <?=(int)$u['id']===(int)$_SESSION['id']?'disabled':''?> data-confirm="Hapus akun <?=e($u['nama'])?>?"><i class="fa-solid fa-trash"></i></button></form></div></article><?php endforeach;?></div><div id="userSearchEmpty" class="empty-state" hidden><i class="fa-solid fa-user-slash"></i><h3>Anggota tidak ditemukan</h3><p>Coba kata pencarian lain.</p></div>
</div></section>
<div class="modal" id="createUser"><div class="modal-panel"><header class="modal-header"><div class="modal-header-copy"><h2>Tambah anggota</h2><p>Buat akun staf atau Kepala Bagian baru.</p></div><button class="icon-btn" data-modal-close><i class="fa-solid fa-xmark"></i></button></header><form method="post" data-submit-lock><?=csrf_field()?><input type="hidden" name="action" value="create"><div class="modal-body"><div class="form-grid"><div class="field field-full"><label>Nama lengkap</label><input name="nama" maxlength="50" required></div><div class="field"><label>Email</label><input name="email" type="email" required></div><div class="field"><label>Username</label><input name="username" pattern="[A-Za-z0-9._-]{3,50}" required></div><div class="field"><label>Role</label><select name="role"><option value="staff">Staf</option><option value="kabag">Kepala Bagian</option></select></div><div class="field"><label>Password awal</label><input name="password" type="password" minlength="8" required></div></div></div><footer class="modal-footer"><button class="btn btn-outline" type="button" data-modal-close>Batal</button><button class="btn btn-primary" type="submit">Simpan</button></footer></form></div></div>
<div class="modal" id="editUser"><div class="modal-panel"><header class="modal-header"><div class="modal-header-copy"><h2>Edit anggota</h2><p>Kosongkan password bila tidak ingin menggantinya.</p></div><button class="icon-btn" data-modal-close><i class="fa-solid fa-xmark"></i></button></header><form method="post" data-submit-lock><?=csrf_field()?><input type="hidden" name="action" value="update"><input type="hidden" name="id" id="editUserId"><div class="modal-body"><div class="form-grid"><div class="field field-full"><label>Nama</label><input name="nama" id="editUserName" required></div><div class="field"><label>Email</label><input name="email" id="editUserEmail" type="email" required></div><div class="field"><label>Username</label><input name="username" id="editUserUsername" required></div><div class="field"><label>Role</label><select name="role" id="editUserRole"><option value="staff">Staf</option><option value="kabag">Kepala Bagian</option></select></div><div class="field"><label>Password baru</label><input name="password" type="password" minlength="8" placeholder="Opsional"></div></div></div><footer class="modal-footer"><button class="btn btn-outline" type="button" data-modal-close>Batal</button><button class="btn btn-primary" type="submit">Perbarui</button></footer></form></div></div>
<?php $script=<<<'JS'
<script>
function editUser(d){document.getElementById('editUserId').value=d.id;document.getElementById('editUserName').value=d.nama;document.getElementById('editUserEmail').value=d.email;document.getElementById('editUserUsername').value=d.username;document.getElementById('editUserRole').value=d.role;openModal('editUser')}
</script>
JS;
render_app_end($script); ?>